import{_ as r,o as t,c as a,a2 as s}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Chapter 7: Streaming Responses","description":"Implementing server-sent events, token-by-token rendering, and partial tool call assembly for real-time AI responses.","frontmatter":{"title":"Chapter 7: Streaming Responses","description":"Implementing server-sent events, token-by-token rendering, and partial tool call assembly for real-time AI responses."},"headers":[],"relativePath":"learn/project/07-streaming-responses/index.md","filePath":"learn/project/07-streaming-responses/index.md"}'),n={name:"learn/project/07-streaming-responses/index.md"};function i(o,e,l,p,c,m){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="streaming-responses" tabindex="-1">Streaming Responses <a class="header-anchor" href="#streaming-responses" aria-label="Permalink to &quot;Streaming Responses&quot;">​</a></h1><p>Waiting for a complete response before displaying anything to the user is unacceptable in an interactive coding agent. This chapter teaches you how to implement streaming from the ground up, turning your agent from a batch processor into a responsive, real-time assistant.</p><p>You will start with the Server-Sent Events (SSE) protocol and chunked transfer encoding that underpin the Anthropic streaming API. From there, you will build a token-by-token rendering pipeline that displays text as it arrives, and tackle the tricky problem of assembling partial tool call JSON fragments into complete, parseable tool invocations.</p><p>The chapter culminates in a streaming state machine that manages the full lifecycle of a streamed response, from connection setup through content delivery to graceful completion or error recovery. You will also implement interrupt handling so users can cancel mid-stream, backpressure mechanisms to prevent memory blowouts on slow terminals, and reconnection logic for unreliable networks.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Parse and consume Server-Sent Events (SSE) streams from the Anthropic API</li><li>Render tokens incrementally as they arrive for a responsive user experience</li><li>Assemble partial JSON fragments into complete tool call invocations</li><li>Build a state machine that tracks streaming lifecycle phases</li><li>Handle interrupts, backpressure, and error recovery during streaming</li><li>Implement reconnection with exponential backoff for dropped connections</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/07-streaming-responses/01-why-streaming.html">Why Streaming</a></li><li><a href="/project/07-streaming-responses/02-sse-protocol.html">SSE Protocol</a></li><li><a href="/project/07-streaming-responses/03-chunked-transfer.html">Chunked Transfer</a></li><li><a href="/project/07-streaming-responses/04-token-by-token-rendering.html">Token By Token Rendering</a></li><li><a href="/project/07-streaming-responses/05-partial-tool-call-assembly.html">Partial Tool Call Assembly</a></li><li><a href="/project/07-streaming-responses/06-buffering-strategies.html">Buffering Strategies</a></li><li><a href="/project/07-streaming-responses/07-interrupt-handling.html">Interrupt Handling</a></li><li><a href="/project/07-streaming-responses/08-backpressure.html">Backpressure</a></li><li><a href="/project/07-streaming-responses/09-streaming-state-machine.html">Streaming State Machine</a></li><li><a href="/project/07-streaming-responses/10-error-recovery.html">Error Recovery</a></li><li><a href="/project/07-streaming-responses/11-reconnection.html">Reconnection</a></li><li><a href="/project/07-streaming-responses/12-progress-display.html">Progress Display</a></li><li><a href="/project/07-streaming-responses/13-real-time-ui-updates.html">Real Time UI Updates</a></li><li><a href="/project/07-streaming-responses/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 2: HTTP client setup and Anthropic API interaction patterns</li><li>Chapter 3: The agentic loop and message processing pipeline</li></ul>',10)])])}const d=r(n,[["render",i]]);export{g as __pageData,d as default};
